"use client";

import type { LandingPageData } from "@/types/landing-page";
import { HeroSection } from "./HeroSection";
import { FactCheckSection } from "./FactCheckSection";
import { OverviewSection } from "./OverviewSection";
import { LocationSection } from "./LocationSection";
import { DevelopmentSection } from "./DevelopmentSection";
import { FacilitiesSection } from "./FacilitiesSection";
import { InteriorSection } from "./InteriorSection";
import { FloorPlanSection } from "./FloorPlanSection";
import { ContactFormSection } from "./ContactFormSection";

interface TemplateBProps {
  data: LandingPageData;
  projectId?: string;
}

/**
 * Template B - 구조화된 부동산 랜딩 (보라 배너 + zigbang 로고 스타일)
 */
export function TemplateB({ data, projectId }: TemplateBProps) {
  const zigbangLogoURL = data.hero.zigbangLogoURL;
  let pointIndex = 1;
  const getPointLabel = () => `POINT ${pointIndex++}`;

  return (
    <div className="mx-auto min-h-screen w-full max-w-md overflow-hidden bg-gray-50">
      <HeroSection data={data.hero} />
      {data.factCheck?.enabled !== false && (
        <FactCheckSection data={{ ...data.factCheck, pointLabel: getPointLabel() }} zigbangLogoURL={zigbangLogoURL} />
      )}
      {data.overview?.enabled !== false && (
        <OverviewSection data={data.overview} />
      )}
      {data.location?.enabled !== false && (
        <LocationSection data={{ ...data.location, pointLabel: getPointLabel() }} zigbangLogoURL={zigbangLogoURL} />
      )}
      {data.development?.enabled !== false && (
        <DevelopmentSection data={{ ...data.development, pointLabel: getPointLabel() }} zigbangLogoURL={zigbangLogoURL} />
      )}
      {data.facilities?.enabled !== false && (
        <FacilitiesSection data={{ ...data.facilities, pointLabel: getPointLabel() }} zigbangLogoURL={zigbangLogoURL} />
      )}
      {data.interior?.enabled !== false && (
        <InteriorSection data={{ ...data.interior, pointLabel: getPointLabel() }} zigbangLogoURL={zigbangLogoURL} />
      )}
      {data.floorPlan?.enabled !== false && (
        <FloorPlanSection data={{ ...data.floorPlan, pointLabel: getPointLabel() }} zigbangLogoURL={zigbangLogoURL} />
      )}
      <ContactFormSection data={data.contactForm} projectId={projectId} />
    </div>
  );
}
